const input = $input.first().json;
const ctx = input.execution_context;

if (!ctx) throw new Error('[resume_intelligence] Missing execution_context');
if (!ctx.resume_id) throw new Error('[resume_intelligence] Missing resume_id');
if (!ctx.user_id) throw new Error('[resume_intelligence] Missing user_id');

// We expect the raw text to be injected by the orchestrator/upload step
// If not present in ctx, we might need to fetch it from DB, but for Phase 3 we assume it's passed.
if (!ctx.resume_text) throw new Error('[resume_intelligence] Missing resume_text in context');

console.log(`[resume_intelligence] START | exec_id=${ctx.execution_id} | resume_id=${ctx.resume_id}`);

return [{ json: ctx }];

const crypto = require('crypto');
const ctx = $input.first().json;

// Clean text, limit to 50,000 chars (~12k tokens) to prevent context explosion
let text = (ctx.resume_text || '').replace(/\r\n/g, '\n').trim();
if (text.length > 50000) {
  text = text.substring(0, 50000);
  ctx.warnings = ctx.warnings || [];
  ctx.warnings.push({ agent: 'resume_intelligence', warning: 'Resume truncated to 50k chars', timestamp: new Date().toISOString() });
}

const hash = crypto.createHash('sha256').update(text).digest('hex');
const cacheKey = `resume_profile:${ctx.resume_id}:${hash}`;

return [{ json: { ...ctx, resume_text_clean: text, text_hash: hash, cache_key: cacheKey } }];

const cache = $input.first().json.value;
const ctx = $('Clean & Hash').item.json;

console.log(`[resume_intelligence] CACHE HIT | resume_id=${ctx.resume_id}`);

return [{
  json: {
    ...ctx,
    results: {
      ...(ctx.results || {}),
      resume_profile: cache.resume_profile,
      career_goals: cache.career_profile
    },
    agents_completed: [...(ctx.agents_completed || []), 'resume_intelligence']
  }
}];

const ctx = $('Clean & Hash').item.json;
const prompt = `You are an expert Resume Intelligence Engine. Extract every piece of professional info into JSON.

Raw Resume:
${ctx.resume_text_clean}`;
// In a real n8n instance, we'd read this from the file system or pass it via config

return [{
  json: {
    prompt,
    model: $env.MODEL_RESUME_PARSING || 'google/gemini-flash-1.5'
  }
}];

