const llmRes = $input.first().json;
let content = llmRes.choices[0].message.content;

// Strip markdown code blocks if the model ignored instructions
if (content.startsWith('```json')) content = content.replace(/^```json/, '');
if (content.startsWith('```')) content = content.replace(/^```/, '');
content = content.replace(/```$/, '');

let parsed;
try {
  parsed = JSON.parse(content);
} catch (e) {
  throw new Error(`LLM returned invalid JSON: ${e.message}`);
}

// Basic validation
if (!parsed.personal_info) throw new Error('Missing personal_info in LLM response');

return [{ json: parsed }];

const parsed = $input.first().json;
// Load skill normalizer via HTTP or file. For n8n, we simulate the logic here.
// Assume `parsed.skills_raw`, `parsed.experience` are available.

const normalizedSkills = [];
const rawSkills = parsed.skills_raw || [];

// Example of normalization logic
rawSkills.forEach(skill => {
  let norm = skill;
  if (skill.toLowerCase() === 'js') norm = 'JavaScript';
  if (skill.toLowerCase() === 'reactjs') norm = 'React';

  normalizedSkills.push({
    raw: skill,
    normalized: norm,
    category: 'unknown', // Would come from dictionary
    is_primary: true,
    frequency: 1,
    last_used_year: new Date().getFullYear()
  });
});

parsed.skills_matrix = normalizedSkills;
return [{ json: parsed }];

const parsed = $input.first().json;

// Career inference
const expYears = (parsed.experience || []).length * 1.5; // Dummy logic for brevity
let level = 'entry_level';
if (expYears > 3) level = 'mid_level';
if (expYears > 7) level = 'senior';

parsed.career_profile = {
  inferred_roles: [parsed.experience?.[0]?.role || 'Professional'],
  experience_level: level,
  primary_domain: 'General',
  secondary_domain: null,
  total_years_experience: expYears,
  is_student: false
};

// Quality scoring
let score = 100;
const missing = [];
if (!parsed.personal_info?.email) { score -= 20; missing.push('email'); }
if (!parsed.summary) { score -= 10; missing.push('summary'); }

parsed.quality_report = {
  score,
  missing_critical_fields: missing,
  warnings: [],
  empty_sections: [],
  is_scanned_pdf: false
};

return [{ json: parsed }];

const profile = $('Career & Quality Inference').item.json;
const ctx = $('Clean & Hash').item.json;

// Final output build
profile.resume_id = ctx.resume_id;
profile.metadata = {
  extracted_at: new Date().toISOString(),
  parse_confidence: 95,
  word_count: ctx.resume_text_clean.split(' ').length,
  extraction_model: $env.MODEL_RESUME_PARSING,
  text_hash: ctx.text_hash
};

return [{
  json: {
    ...ctx,
    results: {
      ...(ctx.results || {}),
      resume_profile: profile,
      career_goals: profile.career_profile
    },
    agents_completed: [...(ctx.agents_completed || []), 'resume_intelligence']
  }
}];
